293:     // Visibility for tests
294:     void setupRecordPruning() {
295:         log.debug("Scheduling share-group state topic prune job.");
296:         timer.add(new TimerTask(config.shareCoordinatorTopicPruneIntervalMs()) {
297:             @Override
298:             public void run() {
299:                 if (!shouldRunPeriodicJob) {
300:                     return;
301:                 }
302:                 List<CompletableFuture<Void>> futures = new ArrayList<>();
303:                 runtime.activeTopicPartitions().forEach(tp -> futures.add(performRecordPruning(tp)));
304: 
305:                 CompletableFuture.allOf(futures.toArray(new CompletableFuture<?>[]{}))
306:                     .whenComplete((res, exp) -> {
307:                         if (exp != null) {
308:                             log.error("Received error in share-group state topic prune.", exp);
309:                         }
310:                         // Perpetual recursion, failure or not.
311:                         setupRecordPruning();
312:                     });
313:             }
314:         });
315:     }
316: 
317:     private CompletableFuture<Void> performRecordPruning(TopicPartition tp) {
318:         CompletableFuture<Void> fut = new CompletableFuture<>();
319: 
320:         runtime.scheduleWriteOperation(
321:             "write-state-record-prune",
322:             tp,
323:             Duration.ofMillis(config.shareCoordinatorWriteTimeoutMs()),
324:             ShareCoordinatorShard::lastRedundantOffset
325:         ).whenComplete((result, exception) -> {
326:             if (exception != null) {
327:                 log.debug("Last redundant offset for tp {} lookup threw an error.", tp, exception);
328:                 Errors error = Errors.forException(exception);
329:                 // These errors might result from partition metadata not loaded
330:                 // or shard re-election. Will cause unnecessary noise, hence not logging
331:                 if (!(error.equals(Errors.COORDINATOR_LOAD_IN_PROGRESS) || error.equals(Errors.NOT_COORDINATOR))) {
332:                     log.error("Last redundant offset lookup for tp {} threw an error.", tp, exception);
333:                     fut.completeExceptionally(exception);
334:                     return;
335:                 }
336:                 fut.complete(null);
337:                 return;
338:             }
339:             if (result.isPresent()) {
340:                 Long off = result.get();
341:                 Long lastPrunedOffset = lastPrunedOffsets.get(tp);
342:                 if (lastPrunedOffset != null && lastPrunedOffset.longValue() == off) {
343:                     log.debug("{} already pruned till offset {}", tp, off);
344:                     fut.complete(null);
345:                     return;
346:                 }
347: 
348:                 log.debug("Pruning records in {} till offset {}.", tp, off);
349:                 writer.deleteRecords(tp, off)
350:                     .whenComplete((res, exp) -> {
351:                         if (exp != null) {
352:                             log.error("Exception while deleting records in {} till offset {}.", tp, off, exp);
353:                             fut.completeExceptionally(exp);
354:                             return;
355:                         }
356:                         shareCoordinatorMetrics.recordPrune(
357:                             off,
358:                             tp
359:                         );
360:                         fut.complete(null);
361:                         // Best effort prevention of issuing duplicate delete calls.
362:                         lastPrunedOffsets.put(tp, off);
363:                     });
364:             } else {
365:                 log.debug("No offset value for tp {} found.", tp);
366:                 fut.complete(null);
367:             }
368:         });
369:         return fut;
370:     }
